(window.webpackJsonp=window.webpackJsonp||[]).push([[523],{818:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string[]}</span> <span class=\\"hljs-variable\\">names</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getFolderNames = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">names</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">let</span> used={}\\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;names.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> name=names[i]\\n    <span class=\\"hljs-keyword\\">let</span> nxtName=name\\n    <span class=\\"hljs-keyword\\">if</span>(used[name]==<span class=\\"hljs-literal\\">null</span>){\\n      used[name]=<span class=\\"hljs-number\\">0</span>\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      <span class=\\"hljs-keyword\\">let</span> nxtUnique=used[name]\\n      nxtUnique+=<span class=\\"hljs-number\\">1</span>\\n      nxtName=name+<span class=\\"hljs-string\\">`(<span class=\\"hljs-subst\\">${nxtUnique}</span>)`</span> \\n      <span class=\\"hljs-keyword\\">while</span>(used[nxtName]!=<span class=\\"hljs-literal\\">null</span>){\\n        nxtUnique++\\n        nxtName=nxtName.slice(<span class=\\"hljs-number\\">0</span>,nxtName.length<span class=\\"hljs-number\\">-3</span>)+<span class=\\"hljs-string\\">`(<span class=\\"hljs-subst\\">${nxtUnique}</span>)`</span>\\n         <span class=\\"hljs-comment\\">// console.log(nxtName)</span>\\n      }\\n      used[nxtName]=<span class=\\"hljs-number\\">0</span>\\n      used[name]=nxtUnique\\n    }\\n    res.push(nxtName)\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"making-file-names-unique","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u957f\u5ea6\u4e3a <code>n</code> \u7684\u5b57\u7b26\u4e32\u6570\u7ec4 <code>names</code> \u3002\u4f60\u5c06\u4f1a\u5728\u6587\u4ef6\u7cfb\u7edf\u4e2d\u521b\u5efa <code>n</code> \u4e2a\u6587\u4ef6\u5939\uff1a\u5728\u7b2c <code>i</code> \u5206\u949f\uff0c\u65b0\u5efa\u540d\u4e3a <code>names[i]</code> \u7684\u6587\u4ef6\u5939\u3002</p>\\n\\n<p>\u7531\u4e8e\u4e24\u4e2a\u6587\u4ef6 <strong>\u4e0d\u80fd</strong> \u5171\u4eab\u76f8\u540c\u7684\u6587\u4ef6\u540d\uff0c\u56e0\u6b64\u5982\u679c\u65b0\u5efa\u6587\u4ef6\u5939\u4f7f\u7528\u7684\u6587\u4ef6\u540d\u5df2\u7ecf\u88ab\u5360\u7528\uff0c\u7cfb\u7edf\u4f1a\u4ee5 <code>(k)</code> \u7684\u5f62\u5f0f\u4e3a\u65b0\u6587\u4ef6\u5939\u7684\u6587\u4ef6\u540d\u6dfb\u52a0\u540e\u7f00\uff0c\u5176\u4e2d <code>k</code> \u662f\u80fd\u4fdd\u8bc1\u6587\u4ef6\u540d\u552f\u4e00\u7684 <strong>\u6700\u5c0f\u6b63\u6574\u6570</strong> \u3002</p>\\n\\n<p>\u8fd4\u56de\u957f\u5ea6\u4e3a<em> <code>n</code></em> \u7684\u5b57\u7b26\u4e32\u6570\u7ec4\uff0c\u5176\u4e2d <code>ans[i]</code> \u662f\u521b\u5efa\u7b2c <code>i</code> \u4e2a\u6587\u4ef6\u5939\u65f6\u7cfb\u7edf\u5206\u914d\u7ed9\u8be5\u6587\u4ef6\u5939\u7684\u5b9e\u9645\u540d\u79f0\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>names = [&quot;pes&quot;,&quot;fifa&quot;,&quot;gta&quot;,&quot;pes(2019)&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[&quot;pes&quot;,&quot;fifa&quot;,&quot;gta&quot;,&quot;pes(2019)&quot;]\\n<strong>\u89e3\u91ca\uff1a</strong>\u6587\u4ef6\u7cfb\u7edf\u5c06\u4f1a\u8fd9\u6837\u521b\u5efa\u6587\u4ef6\u540d\uff1a\\n&quot;pes&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;pes&quot;\\n&quot;fifa&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;fifa&quot;\\n&quot;gta&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;gta&quot;\\n&quot;pes(2019)&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;pes(2019)&quot;\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>names = [&quot;gta&quot;,&quot;gta(1)&quot;,&quot;gta&quot;,&quot;avalon&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[&quot;gta&quot;,&quot;gta(1)&quot;,&quot;gta(2)&quot;,&quot;avalon&quot;]\\n<strong>\u89e3\u91ca\uff1a</strong>\u6587\u4ef6\u7cfb\u7edf\u5c06\u4f1a\u8fd9\u6837\u521b\u5efa\u6587\u4ef6\u540d\uff1a\\n&quot;gta&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;gta&quot;\\n&quot;gta(1)&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;gta(1)&quot;\\n&quot;gta&quot; --&gt; \u6587\u4ef6\u540d\u88ab\u5360\u7528\uff0c\u7cfb\u7edf\u4e3a\u8be5\u540d\u79f0\u6dfb\u52a0\u540e\u7f00 (k)\uff0c\u7531\u4e8e &quot;gta(1)&quot; \u4e5f\u88ab\u5360\u7528\uff0c\u6240\u4ee5 k = 2 \u3002\u5b9e\u9645\u521b\u5efa\u7684\u6587\u4ef6\u540d\u4e3a &quot;gta(2)&quot; \u3002\\n&quot;avalon&quot; --&gt; \u4e4b\u524d\u672a\u5206\u914d\uff0c\u4ecd\u4e3a &quot;avalon&quot;\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>names = [&quot;onepiece&quot;,&quot;onepiece(1)&quot;,&quot;onepiece(2)&quot;,&quot;onepiece(3)&quot;,&quot;onepiece&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[&quot;onepiece&quot;,&quot;onepiece(1)&quot;,&quot;onepiece(2)&quot;,&quot;onepiece(3)&quot;,&quot;onepiece(4)&quot;]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5f53\u521b\u5efa\u6700\u540e\u4e00\u4e2a\u6587\u4ef6\u5939\u65f6\uff0c\u6700\u5c0f\u7684\u6b63\u6709\u6548 k \u4e3a 4 \uff0c\u6587\u4ef6\u540d\u53d8\u4e3a &quot;onepiece(4)&quot;\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>names = [&quot;wano&quot;,&quot;wano&quot;,&quot;wano&quot;,&quot;wano&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[&quot;wano&quot;,&quot;wano(1)&quot;,&quot;wano(2)&quot;,&quot;wano(3)&quot;]\\n<strong>\u89e3\u91ca\uff1a</strong>\u6bcf\u6b21\u521b\u5efa\u6587\u4ef6\u5939 &quot;wano&quot; \u65f6\uff0c\u53ea\u9700\u589e\u52a0\u540e\u7f00\u4e2d k \u7684\u503c\u5373\u53ef\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>names = [&quot;kaido&quot;,&quot;kaido(1)&quot;,&quot;kaido&quot;,&quot;kaido(1)&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[&quot;kaido&quot;,&quot;kaido(1)&quot;,&quot;kaido(2)&quot;,&quot;kaido(1)(1)&quot;]\\n<strong>\u89e3\u91ca\uff1a</strong>\u6ce8\u610f\uff0c\u5982\u679c\u542b\u540e\u7f00\u6587\u4ef6\u540d\u88ab\u5360\u7528\uff0c\u90a3\u4e48\u7cfb\u7edf\u4e5f\u4f1a\u6309\u89c4\u5219\u5728\u540d\u79f0\u540e\u6dfb\u52a0\u65b0\u7684\u540e\u7f00 (k) \u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= names.length &lt;= 5 * 10^4</code></li>\\n\\t<li><code>1 &lt;= names[i].length &lt;= 20</code></li>\\n\\t<li><code>names[i]</code> \u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u3001\u6570\u5b57\u548c/\u6216\u5706\u62ec\u53f7\u7ec4\u6210\u3002</li>\\n</ul>\\n","title":"1487. \u4fdd\u8bc1\u6587\u4ef6\u540d\u552f\u4e00","relatedTags":["\u54c8\u5e0c\u8868","\u5b57\u7b26\u4e32"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1487"}')}}]);